class APMConfig:
    """Configuration for the APM system."""
    
    def __init__(
        self,
        service_name="my-python-app",
        server_url=None,
        secret_token=None,
        environment="development",
        capture_body="all",
        capture_headers=True,
        collect_sql_queries=True,
        collect_stack_traces=True,
        transaction_sample_rate=1.0,
        span_frames_min_duration_ms=5,
        stack_trace_limit=50,
        debug=False,
    ):
        self.service_name = service_name
        self.server_url = server_url or os.environ.get("APM_SERVER_URL", "http://localhost:8200")
        self.secret_token = secret_token or os.environ.get("APM_SECRET_TOKEN", "")
        self.environment = environment
        self.capture_body = capture_body  # "off", "errors", "transactions", "all"
        self.capture_headers = capture_headers
