def trace_transaction(name=None, transaction_type="custom"):
    """Decorator to trace a function as a transaction."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            apm = APMClient.get_instance()
            txn_name = name or f"{func.__module__}.{func.__qualname__}"
            transaction = apm.begin_transaction(txn_name, transaction_type)
            try:
                result = func(*args, **kwargs)
                apm.end_transaction(result="success")
                return result
            except Exception as e:
                apm.capture_exception(e)
                apm.end_transaction(result="error")
                raise
        return wrapper
    return decorator


def trace_span(name=None, span_type="custom", subtype=None, action=None):
    """Decorator to trace a function as a span within a transaction."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            apm = APMClient.get_instance()
            span_name = name or f"{func.__module__}.{func.__qualname__}"
            span = apm.begin_span(span_name, span_type, subtype=subtype, action=action)
            try:
                result = func(*args, **kwargs)
                if span:
                    span.end()
                return result
            except Exception as e:
                if span:
                    span.status = "error"
                    span.error = e
                    span.end()
                raise
        return wrapper
    return decorator


