class InstrumentedDatabase:
    """SQLite database wrapper with APM instrumentation."""
    
    def __init__(self, db_path=":memory:", apm_client=None):
        self.db_path = db_path
        self.apm = apm_client or APMClient.get_instance()
        self.connection = sqlite3.connect(db_path)
        self.connection.row_factory = sqlite3.Row
        logger.info(f"Database connected: {db_path}")
    
    def execute(self, query, params=None):
        """Execute a SQL query with APM tracing."""
        span = self.apm.begin_span(
            name=self._get_query_name(query),
            span_type="db",
            subtype="sqlite",
            action="query",
        )
        
        try:
            cursor = self.connection.cursor()
            if params:
                if span and self.apm.config.collect_sql_queries:
                    span.set_sql_context(
                        query=query,
                        db_type="sqlite",
                        db_instance=self.db_path,
                    )
                    span.set_context("params", str(params))
                result = cursor.execute(query, params)
            else:
                if span and self.apm.config.collect_sql_queries:
                    span.set_sql_context(
                        query=query,
                        db_type="sqlite",
                        db_instance=self.db_path,
                    )
                result = cursor.execute(query)
            
            self.connection.commit()
            
            if span:
                span.set_context("rows_affected", cursor.rowcount)
                span.end()
            
            return result
        except Exception as e:
            if span:
                span.status = "error"
                span.error = e
                span.end()
            self.apm.capture_exception(e)
            raise
    
    def fetchall(self, query, params=None):
        """Execute a query and fetch all results."""
        span = self.apm.begin_span(
            name=self._get_query_name(query),
            span_type="db",
            subtype="sqlite",
            action="query",
        )
        
        try:
            cursor = self.connection.cursor()
            if params:
                if span and self.apm.config.collect_sql_queries:
                    span.set_sql_context(query=query, db_type="sqlite", db_instance=self.db_path)
                cursor.execute(query, params)
            else:
                if span and self.apm.config.collect_sql_queries:
                    span.set_sql_context(query=query, db_type="sqlite", db_instance=self.db_path)
                cursor.execute(query)
            
            rows = cursor.fetchall()
            
            if span:
                span.set_context("rows_returned", len(rows))
                span.end()
            
            return [dict(row) for row in rows]
        except Exception as e:
            if span:
                span.status = "error"
                span.error = e
                span.end()
            self.apm.capture_exception(e)
            raise
    
    def _get_query_name(self, query):
        """Extract a readable name from a SQL query."""
        query_stripped = query.strip().upper()
        parts = query_stripped.split()
        if len(parts) >= 2:
            operation = parts[0]
            if operation in ("SELECT", "DELETE") and "FROM" in parts:
                idx = parts.index("FROM")
                if idx + 1 < len(parts):
                    return f"{operation} {parts[idx + 1]}"
            elif operation in ("INSERT", "UPDATE"):
                table = parts[2] if operation == "INSERT" and len(parts) > 2 else parts[1]
                return f"{operation} {table}"
            elif operation in ("CREATE", "DROP", "ALTER"):
                return f"{operation} {' '.join(parts[1:3])}"
        return query[:50]
    
    def close(self):
        self.connection.close()
        logger.info("Database connection closed")


