class InstrumentedHTTPHandler:
    """Simulated HTTP handler with full APM instrumentation."""
    
    def __init__(self, apm_client=None):
        self.apm = apm_client or APMClient.get_instance()
        self.routes = {}
    
    def route(self, path, method="GET"):
        """Register a route handler."""
        def decorator(func):
            self.routes[(method, path)] = func
            return func
        return decorator
    
    def handle_request(self, method, path, headers=None, body=None, query_params=None):
        """Handle a simulated HTTP request with full APM tracing."""
        transaction = self.apm.begin_transaction(
            name=f"{method} {path}",
            transaction_type="request",
        )
        
        # Capture request context
        request_data = {
            "method": method,
            "url": path,
            "query_params": query_params or {},
        }
        
        if self.apm.config.capture_headers and headers:
            transaction.set_request_context(
                method=method,
                url=path,
                headers=headers,
                body=body if self.apm.config.capture_body in ("all", "transactions") else None,
            )
        else:
            transaction.set_request_context(method=method, url=path)
        
        transaction.set_custom_context("query_params", query_params)
        
        try:
            handler = self.routes.get((method, path))
            if handler is None:
                response_body = {"error": "Not Found"}
                status_code = 404
                transaction.set_response_context(
                    status_code=status_code,
                    headers={"Content-Type": "application/json"},
                    body=response_body,
                )
                self.apm.end_transaction(result=f"HTTP {status_code}")
                return status_code, response_body
            
            # Execute the handler
            response = handler(request_data)
            
            status_code = response.get("status_code", 200)
            response_body = response.get("body", {})
            response_headers = response.get("headers", {"Content-Type": "application/json"})
            
            transaction.set_response_context(
                status_code=status_code,
                headers=response_headers if self.apm.config.capture_headers else None,
                body=response_body if self.apm.config.capture_body in ("all", "transactions") else None,
            )
            
            self.apm.end_transaction(result=f"HTTP {status_code}")
            return status_code, response_body
            
        except Exception as e:
            self.apm.capture_exception(e)
            transaction.set_response_context(
                status_code=500,
                headers={"Content-Type": "application/json"},
                body={"error": str(e)},
            )
            self.apm.end_transaction(result="HTTP 500")
            return 500, {"error": str(e)}


