class InstrumentedExternalCall:
    """Simulated external service calls with APM instrumentation."""
    
    def __init__(self, apm_client=None):
        self.apm = apm_client or APMClient.get_instance()
    
    def call(self, service_name, endpoint, method="GET", payload=None, simulate_latency=0.1):
        """Make a simulated external service call."""
        span = self.apm.begin_span(
            name=f"{method} {service_name}{endpoint}",
            span_type="external",
            subtype="http",
            action=method.lower(),
        )
        
        try:
            if span:
                span.set_context("http", {
                    "method": method,
                    "url": f"https://{service_name}.example.com{endpoint}",
                    "status_code": 200,
                })
            
            # Simulate network latency
            time.sleep(simulate_latency)
            
            result = {
                "status": 200,
                "data": {"service": service_name, "endpoint": endpoint, "success": True},
            }
            
            if span:
                span.end()
            
            return result
            
        except Exception as e:
            if span:
                span.status = "error"
                span.error = e
                span.end()
            raise


