class UserService:
    """Sample service demonstrating APM instrumentation."""
    
    def __init__(self, db, external_client, apm_client=None):
        self.db = db
        self.external = external_client
        self.apm = apm_client or APMClient.get_instance()
        self._init_db()
    
    def _init_db(self):
        """Initialize the database schema."""
        self.db.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT NOT NULL UNIQUE,
                email TEXT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        """)
        self.db.execute("""
            CREATE TABLE IF NOT EXISTS user_activities (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                activity TEXT NOT NULL,
                timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(id)
            )
        """)
    
    @trace_span(name="UserService.create_user", span_type="app", subtype="service")
    def create_user(self, username, email):
        """Create a new user."""
        self.db.execute(
            "INSERT INTO users (username, email) VALUES (?, ?)",
            (username, email),
        )
        # Simulate calling an email service
        self.external.call(
            "email-service", "/api/v1/welcome",
            method="POST",
            payload={"email": email},
            simulate_latency=0.05,
        )
        return {"username": username, "email": email}
    
    @trace_span(name="UserService.get_user", span_type="app", subtype="service")
    def get_user(self, username):
        """Get a user by username."""
        users = self.db.fetchall(
            "SELECT * FROM users WHERE username = ?", (username,)
        )
        return users[0] if users else None
    
    @trace_span(name="UserService.list_users", span_type="app", subtype="service")
    def list_users(self):
        """List all users."""
        return self.db.fetchall("SELECT * FROM users ORDER BY created_at DESC")
    
    @trace_span(name="UserService.log_activity", span_type="app", subtype="service")
    def log_activity(self, user_id, activity):
        """Log user activity."""
        self.db.execute(
            "INSERT INTO user_activities (user_id, activity) VALUES (?, ?)",
            (user_id, activity),
        )
        # Simulate calling analytics service
        self.external.call(
            "analytics-service", "/api/v1/events",
            method="POST",
            payload={"user_id": user_id, "activity": activity},
            simulate_latency=0.03,
        )
    
    @trace_span(name="UserService.get_user_activities", span_type="app", subtype="service")
    def get_user_activities(self, user_id):
        """Get activities for a user."""
        return self.db.fetchall(
            "SELECT * FROM user_activities WHERE user_id = ? ORDER BY timestamp DESC",
            (user_id,),
        )
    
    @trace_span(name="UserService.complex_operation", span_type="app", subtype="service")
    def complex_operation(self, username):
        """A complex operation involving multiple DB queries and external calls."""
        user = self.get_user(username)
        if not user:
            raise ValueError(f"User not found: {username}")
        
        activities = self.get_user_activities(user["id"])
        
        # Simulate calling recommendation service
        recommendations = self.external.call(
            "recommendation-service",
            f"/api/v1/users/{user['id']}/recommendations",
            simulate_latency=0.08,
        )
        
        # Simulate some processing
        time.sleep(0.02)
        
        return {
            "user": user,
            "activities": activities,
            "recommendations": recommendations.get("data"),
        }


def main():
    """Main application demonstrating full APM instrumentation."""
    
    # Initialize APM with full configuration
    config = APMConfig(
        service_name="demo-user-service",
        environment="development",
        capture_body="all",
        capture_headers=True,
        collect_sql_queries=True,
        collect_stack_traces=True,
        transaction_sample_rate=1.0,
        debug=True,
    )
    
    apm = APMClient.get_instance(config)
    
    # Initialize instrumented components
    db = InstrumentedDatabase(":memory:", apm)
    external = InstrumentedExternalCall(apm)
    user_service = UserService(db, external, apm)
    
    # Set up HTTP handler
    http = InstrumentedHTTPHandler(apm)
    
    @http.route("/api/users", "POST")
    def create_user_handler(request):
        user = user_service.create_user("john_doe", "john@example.com")
        return {"status_code": 201, "body": user}
    
    @http.route("/api/users", "GET")
    def list_users_handler(request):
        users = user_service.list_users()
        return {"status_code": 200, "body": {"users": users}}
    
    @http.route("/api/users/john_doe", "GET")
    def get_user_handler(request):
        user = user_service.get_user("john_doe")
        if user:
            return {"status_code": 200, "body": user}
        return {"status_code": 404, "body": {"error": "User not found"}}
    
    @http.route("/api/users/john_doe/profile", "GET")
    def get_user_profile_handler(request):
        result = user_service.complex_operation("john_doe")
        return {"status_code": 200, "body": result}
    
    @http.route("/api/error", "GET")
    def error_handler(request):
        raise RuntimeError("Something went terribly wrong!")
    
    print("\n" + "=" * 70)
    print("APM INSTRUMENTED APPLICATION DEMO")
    print("=" * 70)
    
    # Scenario 1: Create a user
    print("\n--- Scenario 1: Create User ---")
    status, body = http.handle_request(
        "POST", "/api/users",
        headers={"Content-Type": "application/json", "Authorization": "Bearer token123"},
        body=json.dumps({"username": "john_doe", "email": "john@example.com"}),
    )
    print(f"Response: {status} - {json.dumps(body, default=str)}")
    
    # Scenario 2: List users
    print("\n--- Scenario 2: List Users ---")
    status, body = http.handle_request(
        "GET", "/api/users",
        headers={"Accept": "application/json"},
    )
    print(f"Response: {status} - {json.dumps(body, default=str)}")
    
    # Scenario 3: Get specific user
    print("\n--- Scenario 3: Get User ---")
    status, body = http.handle_request(
        "GET", "/api/users/john_doe",
        headers={"Accept": "application/json"},
    )
    print(f"Response: {status} - {json.dumps(body, default=str)}")
    
    # Scenario 4: Log some activities and retrieve profile
    print("\n--- Scenario 4: Log Activities and Get Profile ---")
    txn = apm.begin_transaction("log-activities", "background")
    user_service.log_activity(1, "login")
    user_service.log_activity(1, "view_dashboard")
    user_service.log_activity(1, "update_profile")
    apm.end_transaction(result="success")
    
    status, body = http.handle_request(
        "GET", "/api/users/john_doe/profile",
        headers={"Accept": "application/json", "X-Request-ID": "req-12345"},
    )
    print(f"Response: {status} - {json.dumps(body, default=str)}")
    
    # Scenario 5: Error handling
    print("\n--- Scenario 5: Error Handling ---")
    status, body = http.handle_request("GET", "/api/error")
    print(f"Response: {status} - {json.dumps(body, default=str)}")
    
    # Scenario 6: 404 Not Found
    print("\n--- Scenario 6: Not Found ---")
    status, body = http.handle_request("GET", "/api/nonexistent")
    print(f"Response: {status} - {json.dumps(body, default=str)}")
    
    # Scenario 7: Transaction with decorated function
    print("\n--- Scenario 7: Decorated Function Transaction ---")
    
    @trace_transaction(name="batch-process-users", transaction_type="background")
    def batch_process():
        users = user_service.list_users()
        for user in users:
            user_service.log_activity(user["id"], "batch_process")
        time.sleep(0.05)  # Simulate processing
        return users
    
    batch_process()
    
    # Print overall statistics
    print("\n" + "=" * 70)
    print("APM STATISTICS SUMMARY")
    print("=" * 70)
    stats = apm.get_statistics()
    print(f"Total Transactions: {stats['total_transactions']}")
    print(f"Total Spans: {stats['total_spans']}")
    print(f"Total Errors: {stats['total_errors']}")
    print(f"Average Duration: {stats['average_duration_ms']:.2f}ms")
    print(f"Error Rate: {stats['error_rate_percent']:.1f}%")
    print("\nSlowest Transactions:")
    for txn_info in stats["slowest_transactions"]:
        print(f"  {txn_info['name']}: {txn_info['duration_ms']:.2f}ms")
    
    # Clean up
    db.close()
    print("\nApplication finished. APM data has been collected and reported.")


