def setup_elastic_apm():
    """
    Setup Elastic APM client if the library is available.
    This provides integration with the Elastic APM server.
    """
    try:
        import elasticapm
        
        client = elasticapm.Client(
            service_name=os.environ.get("APM_SERVICE_NAME", "my-python-app"),
            server_url=os.environ.get("APM_SERVER_URL", "http://localhost:8200"),
            secret_token=os.environ.get("APM_SECRET_TOKEN", ""),
            environment=os.environ.get("APM_ENVIRONMENT", "development"),
            capture_body="all",
            capture_headers=True,
            collect_local_variables="all",
            transaction_sample_rate=1.0,
            span_frames_min_duration="5ms",
            stack_trace_limit=50,
            auto_log_stacks=True,
            debug=True,
        )
        
        logger.info("Elastic APM client initialized successfully")
        return client
        
    except ImportError:
        logger.info(
            "elastic-apm not installed. Using built-in APM implementation. "
            "Install with: pip install elastic-apm"
        )
        return None


if __name__ == "__main__":
    # Try to use Elastic APM if available
    elastic_client = setup_elastic_apm()
    
    # Run the demo application with built-in APM
    main()